import{_ as a,c as r,o as t,ah as o}from"./chunks/framework.9lE7mQ-B.js";const b=JSON.parse('{"title":"前言","description":"","frontmatter":{},"headers":[],"relativePath":"v2/index.md","filePath":"v2/index.md","lastUpdated":1740063505000}'),n={name:"v2/index.md"};function i(l,e,d,c,h,s){return t(),r("div",null,e[0]||(e[0]=[o(`<h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h1><p>当前文档为v2版本，v1版本长时间不维护bug较多所以不再维护。<br> v2版本相对于v1版本进行了一定的优化，主要围绕性能以及功能上的优化，后面会介绍。<br> 为了更好的提供api服务，我在2024-06-10正式决定与小杰合作开发。<br> doc前端使用ShowDoc项目（<a href="https://github.com/star7th/showdoc" target="_blank" rel="noreferrer">https://github.com/star7th/showdoc</a>)<br> api后端使用webman框架(<a href="https://www.workerman.net" target="_blank" rel="noreferrer">https://www.workerman.net</a>)</p><h2 id="关于域名" tabindex="-1">关于域名 <a class="header-anchor" href="#关于域名" aria-label="Permalink to &quot;关于域名&quot;">​</a></h2><p><a href="https://doc.vkeys.cn" title="doc.vkeys.cn" target="_blank" rel="noreferrer">doc.vkeys.cn</a> 相关接口文档<br><a href="https://api.vkeys.cn" title="api.vkeys.cn" target="_blank" rel="noreferrer">api.vkeys.cn</a> 后端接口域名</p><h2 id="api路径及请求规范" tabindex="-1">API路径及请求规范 <a class="header-anchor" href="#api路径及请求规范" aria-label="Permalink to &quot;API路径及请求规范&quot;">​</a></h2><pre><code>- 第二版- API：https://{域名}/v2/{接口分类}/{接口功能}
- 第一版API（废弃）：https://{域名}/v1/{接口分类}/{接口功能}
- 请求方式\`GET\`和\`POST\`任意即可
</code></pre><h2 id="文档路径规范" tabindex="-1">文档路径规范 <a class="header-anchor" href="#文档路径规范" aria-label="Permalink to &quot;文档路径规范&quot;">​</a></h2><p><code>接口分类</code> -&gt; <code>数据提供商</code> -&gt; <code>接口名称（包含多级目录）</code></p><h2 id="新特性" tabindex="-1">新特性 <a class="header-anchor" href="#新特性" aria-label="Permalink to &quot;新特性&quot;">​</a></h2><pre><code>- 使用了连接池、请求合并等技术，具有更高效的请求速度。
- 使用了redis缓存、消息队列等技术，实现高并发环境下正常使用。
- 使用了跨域技术，允许不同域名的情况下访问我站API。
- 使用验证器，在进行接口提交时，API会验证参数是否合法。
- 使用错误处理和日志处理，在程序出现异常时，系统自动中断执行并保存相关信息，以便修复bug。
</code></pre><h2 id="后续开发计划" tabindex="-1">后续开发计划 <a class="header-anchor" href="#后续开发计划" aria-label="Permalink to &quot;后续开发计划&quot;">​</a></h2><ol><li>开发后台管理（学完vue3之后）</li><li>开发QQ音乐相关具体功能（如搜索模块新增搜索歌手、搜索歌词、搜索专辑、搜索歌单等）</li><li>开发网易云音乐相关功能</li><li>开发酷狗音乐相关功能</li><li>开发网站工具类相关功能</li></ol><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><p>落月：<code>1569097443@qq.com</code><br> 小杰：<code>2772655946@qq.com</code><br> QQ群：<code>暂无</code></p><h2 id="关于服务器" tabindex="-1">关于服务器 <a class="header-anchor" href="#关于服务器" aria-label="Permalink to &quot;关于服务器&quot;">​</a></h2><p>数据缓存时间：<code>5分钟 ~ 1天</code>（5分钟内重复请求延长缓存时间，最长不超过1天）<br> QPS限制：<code>暂无</code></p><h2 id="整站调用量-待实现" tabindex="-1">整站调用量（待实现） <a class="header-anchor" href="#整站调用量-待实现" aria-label="Permalink to &quot;整站调用量（待实现）&quot;">​</a></h2><p><a href="https://api.vkeys.cn/Call" target="_blank" rel="noreferrer">https://api.vkeys.cn/Call</a></p>`,18)]))}const u=a(n,[["render",i]]);export{b as __pageData,u as default};
